data class ProfileState(
    val name: String = "",
    val notificationsEnabled: Boolean = false,
    val isLoading: Boolean = false
)

sealed class ProfileIntent {
    data class UpdateName(val name: String) : ProfileIntent()
    object ToggleNotifications : ProfileIntent()
    object Save : ProfileIntent()
}

fun reduce(state: ProfileState, intent: ProfileIntent): ProfileState =
    when (intent) {
        is ProfileIntent.UpdateName -> state.copy(name = intent.name)
        is ProfileIntent.ToggleNotifications -> state.copy(
            notificationsEnabled = !state.notificationsEnabled
        )
        is ProfileIntent.Save -> state.copy(isLoading = true)
    }

