class GetTopArticlesUseCase(
    private val articlesRepo: ArticlesRepository,
    private val userRepo: UserRepository
) {
    operator fun invoke(): Flow<List<Article>> {
        return combine(
            articlesRepo.getArticles(),
            userRepo.getFollowedAuthors()
        ) { articles, followedAuthors ->
            articles
                .filter { it.authorId in followedAuthors }
                .sortedByDescending { it.date }
                .take(10)
        }
    }
}

